const msg = $input.first().json;
const message = msg.message || msg.channel_post || {};
const chatId = String(message.chat?.id || '');
const voice = message.voice;
const text = (message.text || message.caption || '').trim();

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};
if (!staticData.pending) staticData.pending = {};

let inputType = 'text';
let voiceFileId = '';
if (voice && voice.file_id) {
  inputType = 'voice';
  voiceFileId = voice.file_id;
}

const lower = text.toLowerCase();
const isNew = inputType === 'text' && lower === '/new';
const isPostCommand = inputType === 'text' && lower === '/post';

if (isNew) {
  const id = Date.now().toString(36) + Math.random().toString(36).slice(2);
  staticData.sessions[chatId] = id;
  staticData.pending[chatId] = null;
} else if (!staticData.sessions[chatId]) {
  const id = Date.now().toString(36) + Math.random().toString(36).slice(2);
  staticData.sessions[chatId] = id;
}

const pendingPost = staticData.pending[chatId] || null;
const isPost = isPostCommand && !!pendingPost;

return [{
  json: {
    chatId,
    inputType,
    text,
    voiceFileId,
    isNew,
    isPost,
    sessionId: staticData.sessions[chatId],
    pendingPost
  }
}];

const agentOutput = $input.first().json.response || $input.first().json.text || $input.first().json.output || '';
const chatId = $('Extract Context').item.json.chatId;

const postMatch = agentOutput.match(/<post>([\s\S]*?)<\/post>/);
const postContent = postMatch ? postMatch[1].trim() : null;

let textContent = agentOutput;
if (postMatch) textContent = textContent.replace(postMatch[0], '').trim();

if (postContent) {
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.pending) staticData.pending = {};
  staticData.pending[chatId] = postContent;
}

return [{
  json: {
    chatId,
    textContent,
    postContent,
    hasPost: !!postContent,
    fullOutput: agentOutput
  }
}];

const blocks = $input.all().map(i => i.json);
const out = [];

function rtToMd(rt) {
  if (!Array.isArray(rt)) return '';
  return rt.map(r => {
    let t = r.plain_text !== undefined ? r.plain_text : (r.text && r.text.content) || '';
    const a = r.annotations || {};
    if (a.code) t = '`' + t + '`';
    if (a.bold) t = '**' + t + '**';
    if (a.italic) t = '*' + t + '*';
    return t;
  }).join('');
}

for (const b of blocks) {
  const type = b.type;
  if (!type) continue;
  const d = b[type] || {};
  const t = rtToMd(d.rich_text || []);
  switch (type) {
    case 'paragraph': if (t) { out.push(t); out.push(''); } break;
    case 'heading_1': out.push(''); out.push('# ' + t); out.push(''); break;
    case 'heading_2': out.push(''); out.push('## ' + t); out.push(''); break;
    case 'heading_3': out.push(''); out.push('### ' + t); out.push(''); break;
    case 'bulleted_list_item': out.push('- ' + t); break;
    case 'numbered_list_item': out.push('1. ' + t); break;
    case 'quote': out.push('> ' + t); out.push(''); break;
    case 'callout': { const emoji = (d.icon && d.icon.emoji) || ''; out.push('> ' + (emoji ? emoji + ' ' : '') + t); out.push(''); break; }
    case 'divider': out.push(''); out.push('---'); out.push(''); break;
    case 'code': out.push('```' + (d.language || '')); out.push(t); out.push('```'); out.push(''); break;
    case 'to_do': out.push('- [ ] ' + t); break;
    case 'toggle': out.push('- ' + t); break;
    default: if (t) { out.push(t); out.push(''); }
  }
}

const markdown = out.join('\n').trim();
return [{ json: { markdown, blockCount: blocks.length } }];

const httpItem = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.promptCache) staticData.promptCache = {};

const AGENT_ID = 'a4';
const CACHE_KEY = `prompt_cache_${AGENT_ID}`;
const TTL_MS = 5 * 60 * 1000;
const now = Date.now();

const rawBody = httpItem.data ?? httpItem.body;
const body = typeof rawBody === 'string' ? rawBody : '';
const httpOk = httpItem.statusCode === 200 && body.trim().length > 100;

let prompt;
let source;

if (httpOk) {
  prompt = body;
  staticData.promptCache[CACHE_KEY] = { prompt, ts: now };
  source = 'live';
} else {
  const cached = staticData.promptCache[CACHE_KEY];
  if (!cached || !cached.prompt) {
    throw new Error(`[${AGENT_ID}] Prompt fetch failed (status ${httpItem.statusCode}) and no cache available`);
  }
  prompt = cached.prompt;
  const ageMin = Math.round((now - cached.ts) / 60000);
  source = (now - cached.ts) > TTL_MS ? 'cache-stale' : 'cache';
  console.log(`[${AGENT_ID}] FALLBACK: HTTP ${httpItem.statusCode}, serving cached prompt (age ${ageMin}m, source=${source})`);
}

const bestPracticesMarkdown = $('Flatten Best Practices').item.json.markdown || '';
prompt = prompt.split("{{ $('Flatten Best Practices').item.json.markdown }}").join(bestPracticesMarkdown);

return [{ json: { prompt, source, agent: AGENT_ID, promptLen: prompt.length } }];

const CHARS_PER_TOKEN = 3.5;
const output = $json.output || '';
const userText = $('Extract Context').item.json.text || '';
const systemPrompt = $('Resolve Prompt').item.json.prompt || '';
const inputChars = systemPrompt.length + userText.length;
const outputChars = output.length;
const inputTokens = Math.ceil(inputChars / CHARS_PER_TOKEN);
const outputTokens = Math.ceil(outputChars / CHARS_PER_TOKEN);
return [{
  json: {
    __monitor_body: {
      agent_name: 'francis',
      provider: 'anthropic',
      model: 'claude-opus-4-6',
      input_tokens: inputTokens,
      output_tokens: outputTokens,
      cache_read_tokens: 0,
      cache_write_tokens: 0,
      workflow_run_id: $execution.id,
      metadata: {
        estimated: true,
        chat_id: $('Extract Context').item.json.chatId,
        session_id: $('Extract Context').item.json.sessionId,
        system_prompt_chars: systemPrompt.length,
        user_text_chars: userText.length,
        output_chars: outputChars
      }
    }
  }
}];

const ctx = $('Extract Context').item.json;
const incoming = $input.first().json;
const transcript = (incoming.text || incoming.transcript || '').trim();
return [{
  json: {
    chatId: ctx.chatId,
    inputType: 'voice',
    text: transcript,
    voiceFileId: ctx.voiceFileId,
    isNew: false,
    isPost: false,
    sessionId: ctx.sessionId,
    pendingPost: ctx.pendingPost
  }
}];
